#include <stdio.h>
#include <string.h>
#include <ctype.h>

void trim(char *s){
    int start=0; while(s[start] && isspace((unsigned char)s[start])) start++;
    int end=strlen(s)-1; while(end>=0 && isspace((unsigned char)s[end])) end--;
    int len=end-start+1;
    memmove(s,s+start,len);
    s[len]='\0';
}

void replaceCats(const char *src, char *dst){
    const char *pat="cats";
    const char *rep="cars";
    while(*src){
        if(strncmp(src,pat,4)==0){
            strcpy(dst,rep);
            src+=4; dst+=4;
        }else{
            *dst=*src; src++; dst++;
        }
    }
    *dst='\0';
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar();
    char line[256];
    for(int i=0;i<T;i++){
        if(!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line,"\n")]='\0';
        trim(line);
        char original[256]; strcpy(original,line);
        char corrected[256]; replaceCats(line, corrected);
        printf("Original sentence: %s\n", original);
        printf("Auto-Corrected sentence: %s\n", corrected);
    }
    return 0;
}

