    for(int i=0;i<T;i++) {
        string line; getline(cin,line);
        string original = trim(line);
        string corrected = original;
        size_t pos=0;
        while((pos=corrected.find("cats",pos))!=string::npos){
            corrected.replace(pos,4,"cars");
            pos+=4;
        }
        cout << "Original sentence: " << original << '\n';
        cout << "Auto-Corrected sentence: " << corrected << '\n';
    }
    return 0;
}

